<?php

namespace App\Services\Providers;

class DemoSpeciesProvider implements SpeciesInfoProviderInterface
{
    public function getSpeciesForLocation(float $lat, float $lng, int $month, bool $isCoastal): array
    {
        $coastalSpecies = [
            ['name' => 'Bass', 'season_rating' => $this->seasonRating($month, [5,6,7,8,9,10]), 'bait' => ['Ragworm', 'Mackerel strip', 'Lures'], 'tackle' => 'Medium spinning rod, 15-20lb braid, size 2/0 hooks', 'best_time' => 'Dawn and dusk, rising tide'],
            ['name' => 'Cod', 'season_rating' => $this->seasonRating($month, [10,11,12,1,2,3]), 'bait' => ['Lugworm', 'Squid', 'Peeler crab'], 'tackle' => 'Beachcaster 12ft, 60-80lb shock leader, 3/0-5/0 hooks', 'best_time' => 'Night sessions, winter storms'],
            ['name' => 'Mackerel', 'season_rating' => $this->seasonRating($month, [5,6,7,8,9]), 'bait' => ['Feathers', 'Sabiki rigs', 'Small lures'], 'tackle' => 'Light spinning rod, 10lb line, mackerel feathers', 'best_time' => 'Mid-morning to afternoon, high tide'],
            ['name' => 'Pollock', 'season_rating' => $this->seasonRating($month, [4,5,6,7,8,9,10]), 'bait' => ['Ragworm', 'Artificial lures', 'Live sandeel'], 'tackle' => 'Medium spinning rod, 15lb braid, soft plastic lures', 'best_time' => 'Early morning, around rocks and kelp'],
            ['name' => 'Whiting', 'season_rating' => $this->seasonRating($month, [9,10,11,12,1,2]), 'bait' => ['Ragworm', 'Fish strip'], 'tackle' => 'Light beachcaster, 2-hook flapper rig, size 2 hooks', 'best_time' => 'Evening into night'],
            ['name' => 'Flounder', 'season_rating' => $this->seasonRating($month, [8,9,10,11,12]), 'bait' => ['Ragworm', 'Peeler crab', 'Harbour rag'], 'tackle' => 'Light rod, running ledger, size 1 hooks, beads', 'best_time' => 'Incoming tide over sand/mud'],
        ];

        $freshwaterSpecies = [
            ['name' => 'Carp', 'season_rating' => $this->seasonRating($month, [4,5,6,7,8,9,10]), 'bait' => ['Boilies', 'Sweetcorn', 'Bread', 'Pellets'], 'tackle' => '12ft carp rod, 15lb line, hair rig, size 8 hooks', 'best_time' => 'Early morning and late evening'],
            ['name' => 'Pike', 'season_rating' => $this->seasonRating($month, [10,11,12,1,2,3]), 'bait' => ['Deadbait (smelt/mackerel)', 'Large lures', 'Spinnerbaits'], 'tackle' => 'Pike rod, 30lb braid, wire trace, size 6 trebles', 'best_time' => 'Morning, overcast days'],
            ['name' => 'Perch', 'season_rating' => $this->seasonRating($month, [9,10,11,12,1,2,3]), 'bait' => ['Worms', 'Maggots', 'Small lures', 'Prawns'], 'tackle' => 'Light spinning rod, 6-8lb line, drop shot rig', 'best_time' => 'Dawn, near structures and cover'],
            ['name' => 'Roach', 'season_rating' => $this->seasonRating($month, [6,7,8,9,10,11]), 'bait' => ['Maggots', 'Bread punch', 'Hemp', 'Casters'], 'tackle' => 'Float rod 13ft, 3lb line, size 18-20 hooks', 'best_time' => 'Steady feeding throughout the day'],
            ['name' => 'Tench', 'season_rating' => $this->seasonRating($month, [5,6,7,8]), 'bait' => ['Sweetcorn', 'Worms', 'Bread', 'Maggots'], 'tackle' => 'Float or feeder rod, 8lb line, size 10-14 hooks', 'best_time' => 'First light, warm mornings'],
            ['name' => 'Barbel', 'season_rating' => $this->seasonRating($month, [6,7,8,9,10,11]), 'bait' => ['Pellets', 'Meat', 'Boilies', 'Hemp'], 'tackle' => '11-12ft feeder rod, 10lb line, hair rig, size 10 hooks', 'best_time' => 'Evening into dark, after rain'],
        ];

        $species = $isCoastal ? $coastalSpecies : $freshwaterSpecies;

        // Sort by season rating
        usort($species, fn($a, $b) => $b['season_rating'] <=> $a['season_rating']);

        return [
            'type' => $isCoastal ? 'coastal' : 'freshwater',
            'month' => $month,
            'species' => $species,
        ];
    }

    private function seasonRating(int $currentMonth, array $peakMonths): int
    {
        if (in_array($currentMonth, $peakMonths)) return rand(7, 10);
        $closest = PHP_INT_MAX;
        foreach ($peakMonths as $m) {
            $diff = min(abs($currentMonth - $m), 12 - abs($currentMonth - $m));
            $closest = min($closest, $diff);
        }
        return max(1, 6 - $closest);
    }

    public function getProviderName(): string
    {
        return 'demo';
    }
}
