<?php

namespace App\Http\Controllers;

use App\Models\Report;
use App\Models\Post;
use App\Models\Comment;
use Illuminate\Http\Request;

class ReportController extends Controller
{
    public function storePostReport(Request $request, Post $post)
    {
        $validated = $request->validate([
            'reason' => 'required|string|max:100',
            'details' => 'nullable|string|max:1000',
        ]);

        $existing = Report::where('user_id', $request->user()->id)
            ->where('reportable_type', Post::class)
            ->where('reportable_id', $post->id)
            ->where('status', 'pending')
            ->exists();

        if ($existing) {
            return back()->with('info', 'You have already reported this post.');
        }

        Report::create([
            'user_id' => $request->user()->id,
            'reportable_type' => Post::class,
            'reportable_id' => $post->id,
            'reason' => $validated['reason'],
            'details' => $validated['details'] ?? null,
        ]);

        return back()->with('success', 'Report submitted. A moderator will review it.');
    }

    public function storeCommentReport(Request $request, Comment $comment)
    {
        $validated = $request->validate([
            'reason' => 'required|string|max:100',
            'details' => 'nullable|string|max:1000',
        ]);

        Report::create([
            'user_id' => $request->user()->id,
            'reportable_type' => Comment::class,
            'reportable_id' => $comment->id,
            'reason' => $validated['reason'],
            'details' => $validated['details'] ?? null,
        ]);

        return back()->with('success', 'Report submitted.');
    }
}
