<boltAction type="file" filePath="app/Http/Controllers/Admin/ReportController.php" contentType="text/x-php">
<?php

namespace App\Http\Controllers\Admin;

use App\Http\Controllers\Controller;
use App\Models\Report;
use App\Models\Post;
use App\Models\Comment;
use Illuminate\Http\Request;

class ReportController extends Controller
{
    public function index(Request $request)
    {
        $query = Report::with(['user', 'reportable', 'reviewer']);

        if ($request->filled('status')) {
            $query->where('status', $request->status);
        } else {
            $query->where('status', 'pending');
        }

        $reports = $query->latest()->paginate(20);

        return view('admin.reports.index', compact('reports'));
    }

    public function resolve(Request $request, Report $report)
    {
        $validated = $request->validate([
            'action' => 'required|in:dismiss,hide_content,delete_content',
            'review_notes' => 'nullable|string|max:1000',
        ]);

        $report->update([
            'status' => $validated['action'] === 'dismiss' ? 'dismissed' : 'resolved',
            'reviewed_by' => $request->user()->id,
            'review_notes' => $validated['review_notes'],
            'reviewed_at' => now(),
        ]);

        if ($validated['action'] === 'hide_content' && $report->reportable) {
            $report->reportable->update(['is_visible' => false]);
        }

        if ($validated['action'] === 'delete_content' && $report->reportable) {
            $report->reportable->delete();
        }

        return back()->with('success', 'Report resolved.');
    }
}
</boltAction>

