<?php

namespace App\Services\Providers;

class DemoWeatherProvider implements WeatherProviderInterface
{
    public function getForecast(float $lat, float $lng, \DateTime $startDate, \DateTime $endDate): array
    {
        $days = [];
        $current = clone $startDate;
        $conditions = ['Partly Cloudy', 'Overcast', 'Light Rain', 'Sunny', 'Cloudy', 'Showers', 'Clear'];
        $i = 0;

        while ($current <= $endDate && $i < 7) {
            $month = (int) $current->format('n');
            $baseTemp = match(true) {
                $month >= 6 && $month <= 8 => rand(15, 24),
                $month >= 3 && $month <= 5 => rand(8, 16),
                $month >= 9 && $month <= 11 => rand(7, 15),
                default => rand(2, 9),
            };

            $days[] = [
                'date' => $current->format('Y-m-d'),
                'condition' => $conditions[array_rand($conditions)],
                'temp_high_c' => $baseTemp + rand(1, 4),
                'temp_low_c' => $baseTemp - rand(2, 5),
                'wind_speed_mph' => rand(3, 25),
                'wind_direction' => ['N', 'NE', 'E', 'SE', 'S', 'SW', 'W', 'NW'][array_rand(['N', 'NE', 'E', 'SE', 'S', 'SW', 'W', 'NW'])],
                'precipitation_chance' => rand(5, 80),
                'humidity' => rand(50, 90),
                'pressure_mb' => rand(995, 1035),
                'sunrise' => '06:' . str_pad(rand(0, 59), 2, '0', STR_PAD_LEFT),
                'sunset' => (rand(16, 21)) . ':' . str_pad(rand(0, 59), 2, '0', STR_PAD_LEFT),
            ];

            $current->modify('+1 day');
            $i++;
        }

        return [
            'location' => ['lat' => $lat, 'lng' => $lng],
            'forecast' => $days,
            'summary' => 'Mixed conditions expected. ' . ($days[0]['precipitation_chance'] > 50 ? 'Pack waterproofs!' : 'Looking decent for fishing.'),
        ];
    }

    public function getProviderName(): string
    {
        return 'demo';
    }
}
