<boltAction type="file" filePath="app/Services/HuntBriefingService.php" contentType="text/x-php">
<?php

namespace App\Services;

use App\Models\Hunt;
use App\Models\HuntBriefing;
use App\Models\HuntChecklistItem;
use App\Services\Providers\WeatherProviderInterface;
use App\Services\Providers\TideProviderInterface;
use App\Services\Providers\SpeciesInfoProviderInterface;
use Illuminate\Support\Facades\DB;

class HuntBriefingService
{
    public function __construct(
        private WeatherProviderInterface $weatherProvider,
        private TideProviderInterface $tideProvider,
        private SpeciesInfoProviderInterface $speciesProvider,
    ) {}

    public function generateBriefing(Hunt $hunt): HuntBriefing
    {
        $lat = $hunt->latitude ?? 51.5074;
        $lng = $hunt->longitude ?? -0.1278;

        $weatherData = $this->weatherProvider->getForecast(
            $lat, $lng,
            $hunt->starts_at->toDateTime(),
            $hunt->ends_at->toDateTime()
        );

        $tideData = null;
        if ($hunt->is_coastal) {
            $tideData = $this->tideProvider->getTides($lat, $lng, $hunt->starts_at->toDateTime());
        }

        $speciesData = $this->speciesProvider->getSpeciesForLocation(
            $lat, $lng,
            $hunt->starts_at->month,
            $hunt->is_coastal
        );

        $suggestions = $this->generateSuggestions($weatherData, $tideData, $speciesData, $hunt);

        return DB::transaction(function () use ($hunt, $weatherData, $tideData, $speciesData, $suggestions) {
            $hunt->briefing()?->delete();
            $hunt->checklistItems()->delete();

            $briefing = HuntBriefing::create([
                'hunt_id' => $hunt->id,
                'weather_data' => $weatherData,
                'tide_data' => $tideData,
                'species_data' => $speciesData,
                'suggestions' => $suggestions,
                'weather_provider' => $this->weatherProvider->getProviderName(),
                'tide_provider' => $this->tideProvider->getProviderName(),
                'species_provider' => $this->speciesProvider->getProviderName(),
                'generated_at' => now(),
                'expires_at' => now()->addHours(6),
            ]);

            $this->generateChecklist($hunt, $weatherData, $speciesData, $suggestions);

            return $briefing;
        });
    }

    private function generateSuggestions(array $weather, ?array $tides, array $species, Hunt $hunt): array
    {
        $suggestions = [];

        // Weather-based suggestions
        $forecast = $weather['forecast'][0] ?? null;
        if ($forecast) {
            if ($forecast['wind_speed_mph'] > 20) {
                $suggestions['weather_warning'] = 'Strong winds expected (' . $forecast['wind_speed_mph'] . 'mph). Consider sheltered spots.';
            }
            if ($forecast['precipitation_chance'] > 60) {
                $suggestions['rain_warning'] = 'High chance of rain (' . $forecast['precipitation_chance'] . '%). Pack waterproofs!';
            }
            if ($forecast['temp_high_c'] < 5) {
                $suggestions['cold_warning'] = 'Cold conditions expected. Layer up and bring hot drinks.';
            }

            $suggestions['timing'] = [];
            if (isset($forecast['sunrise'])) {
                $suggestions['timing'][] = "Sunrise at {$forecast['sunrise']} — great time to start.";
            }
            if (isset($forecast['sunset'])) {
                $suggestions['timing'][] = "Sunset at {$forecast['sunset']} — evening bite possible.";
            }
        }

        // Tide-based suggestions
        if ($tides && !empty($tides['tides'])) {
            $suggestions['tide_tip'] = $tides['tip'] ?? 'Check tide times and fish the changing tide.';
            $suggestions['tide_times'] = $tides['tides'];
        }

        // Species-based suggestions
        $topSpecies = array_slice($species['species'] ?? [], 0, 3);
        $suggestions['top_species'] = $topSpecies;

        // Best time suggestion
        if (!empty($topSpecies)) {
            $suggestions['best_approach'] = "Top target: {$topSpecies[0]['name']}. " .
                "Best time: {$topSpecies[0]['best_time']}. " .
                "Try: " . implode(', ', array_slice($topSpecies[0]['bait'], 0, 2)) . ".";
        }

        return $suggestions;
    }

    private function generateChecklist(Hunt $hunt, array $weather, array $species, array $suggestions): void
    {
        $items = [];
        $order = 0;

        // Essential gear
        $essentials = [
            'Rod and reel (checked and ready)',
            'Landing net',
            'Unhooking mat',
            'Tackle box',
            'Line cutters / scissors',
            'Forceps / disgorger',
            'Bait (see briefing)',
            'Rod rest / bank sticks',
        ];
        foreach ($essentials as $item) {
            $items[] = ['hunt_id' => $hunt->id, 'category' => 'Essential Gear', 'label' => $item, 'sort_order' => $order++, 'created_at' => now(), 'updated_at' => now()];
        }

        // Species-specific tackle
        $topSpecies = $suggestions['top_species'] ?? [];
        foreach (array_slice($topSpecies, 0, 3) as $sp) {
            $items[] = ['hunt_id' => $hunt->id, 'category' => 'Species Tackle', 'label' => "{$sp['name']}: {$sp['tackle']}", 'sort_order' => $order++, 'created_at' => now(), 'updated_at' => now()];
        }

        // Bait list
        $allBait = [];
        foreach ($topSpecies as $sp) {
            foreach ($sp['bait'] as $b) {
                $allBait[$b] = true;
            }
        }
        foreach (array_keys($allBait) as $bait) {
            $items[] = ['hunt_id' => $hunt->id, 'category' => 'Bait', 'label' => $bait, 'sort_order' => $order++, 'created_at' => now(), 'updated_at' => now()];
        }

        // Weather prep
        $weatherItems = ['Sun cream / hat', 'Polarised sunglasses'];
        $forecast = $weather['forecast'][0] ?? null;
        if ($forecast) {
            if ($forecast['precipitation_chance'] > 30) {
                $weatherItems[] = 'Waterproof jacket';
                $weatherItems[] = 'Waterproof trousers';
            }
            if ($forecast['temp_high_c'] < 12) {
                $weatherItems[] = 'Warm layers / thermal';
                $weatherItems[] = 'Gloves';
                $weatherItems[] = 'Hot flask (tea/coffee)';
            }
            if ($forecast['wind_speed_mph'] > 15) {
                $weatherItems[] = 'Windproof layer';
                $weatherItems[] = 'Shelter / brolly';
            }
        }
        foreach ($weatherItems as $item) {
            $items[] = ['hunt_id' => $hunt->id, 'category' => 'Weather Prep', 'label' => $item, 'sort_order' => $order++, 'created_at' => now(), 'updated_at' => now()];
        }

        // Safety & comfort
        $safety = [
            'Phone (fully charged)',
            'First aid kit',
            'Food and water',
            'Headtorch (if fishing into dark)',
            'Fishing licence (check it\'s valid!)',
            'Chair / seat box',
        ];
        foreach ($safety as $item) {
            $items[] = ['hunt_id' => $hunt->id, 'category' => 'Safety & Comfort', 'label' => $item, 'sort_order' => $order++, 'created_at' => now(), 'updated_at' => now()];
        }

        HuntChecklistItem::insert($items);
    }
}
