<?php

namespace App\Services;

use App\Models\User;
use App\Models\Badge;

class BadgeService
{
    public function checkAndAward(User $user): void
    {
        $badges = Badge::all();

        foreach ($badges as $badge) {
            if ($user->badges()->where('badge_id', $badge->id)->exists()) {
                continue;
            }

            $earned = match ($badge->slug) {
                'first-catch' => $user->posts()->visible()->count() >= 1,
                'five-catches' => $user->posts()->visible()->count() >= 5,
                'ten-catches' => $user->posts()->visible()->count() >= 10,
                'species-explorer' => $user->posts()->visible()->whereNotNull('species')->distinct('species')->count('species') >= 3,
                'species-master' => $user->posts()->visible()->whereNotNull('species')->distinct('species')->count('species') >= 10,
                'first-hunt' => $user->hunts()->count() >= 1,
                'five-hunts' => $user->hunts()->count() >= 5,
                'social-angler' => $user->comments()->count() >= 10,
                'popular-catch' => $user->posts()->visible()->withCount('likes')->having('likes_count', '>=', 5)->exists(),
                default => false,
            };

            if ($earned) {
                $user->badges()->attach($badge->id, ['earned_at' => now()]);
            }
        }
    }
}
