<?php

namespace App\Http\Controllers;

use App\Models\User;
use Illuminate\Http\Request;
use Illuminate\Support\Facades\Storage;

class ProfileController extends Controller
{
    public function show(User $user)
    {
        $user->load('roles', 'badges');

        $posts = $user->posts()->visible()
            ->with(['images', 'likes'])
            ->withCount(['likes', 'allComments'])
            ->latest()
            ->paginate(12);

        $hunts = $user->hunts()->latest('starts_at')->limit(5)->get();

        $stats = [
            'posts' => $user->posts()->visible()->count(),
            'species' => $user->posts()->visible()->whereNotNull('species')->distinct('species')->count('species'),
            'hunts' => $user->hunts()->count(),
            'likes_received' => $user->posts()->visible()->withCount('likes')->get()->sum('likes_count'),
        ];

        return view('profile.show', compact('user', 'posts', 'hunts', 'stats'));
    }

    public function edit(Request $request)
    {
        return view('profile.edit', ['user' => $request->user()]);
    }

    public function update(Request $request)
    {
        $validated = $request->validate([
            'name' => 'required|string|max:255',
            'bio' => 'nullable|string|max:500',
            'location' => 'nullable|string|max:255',
            'avatar' => 'nullable|image|mimes:jpeg,jpg,png,webp|max:2048',
        ]);

        $user = $request->user();

        if ($request->hasFile('avatar')) {
            if ($user->avatar_path) {
                Storage::disk('public')->delete($user->avatar_path);
            }
            $validated['avatar_path'] = $request->file('avatar')->store('avatars', 'public');
        }

        unset($validated['avatar']);
        $user->update($validated);

        return redirect()->route('profile.show', $user)->with('success', 'Profile updated!');
    }
}
